","export class DashboardService {
 async getHoursPerEmployee() {
 const response = await fetch(
 "/api/now/stats/x_1952856_employ_1_work_log?sysparm_sum_fields=hours_worked&sysparm_group_by=employee&sysparm_query=status=approved&sysparm_display_value=all",
 {
