 "X-UserToken": (window as any).g_ck
 }
 }
 );
 const data = await response.json();
 return data.result || [];
 }

 async getLeaveRequests() {
 const response = await fetch(
 "/api/now/table/x_1952856_employ_1_leave_request?sysparm_display_value=all&sysparm_query=status=submitted^ORstatus=approved&sysparm_fields=employee,start_date,end_date,leave_type,status&sysparm_limit=20",
 {
 headers: {
 Accept: "application/json",
 "X-UserToken": (window as any).g_ck
 }
 }
 );
 const data = await response.json();
 return data.result || [];
 }

 async getLeaveStats() {
 const response = await fetch(
 "/api/now/stats/x_1952856_employ_1_leave_request?sysparm_count=true&sysparm_group_by=status&sysparm_display_value=all",
 {
 headers: {
 Accept: "application/json",
 "X-UserToken": (window as any).g_ck
 }
 }
 );
 const data = await response.json();
 return data.result || [];
 }
}
","export default function insertStyle(css, tagName = "style") {
 if (!css || typeof window === "undefined")
 return;
 if (tagName === "style") {
 const style = document.createElement("style");
 style.setAttribute("type", "text/css");
 style.innerHTML = css;
 document.head.appendChild(style);
 }
 else if (tagName === "link") {
 const link = document.createElement("link");
 link.setAttribute("rel", "stylesheet");
 link.setAttribute("href", css);
 document.head.appendChild(link);
 }
 return css;
