import "./EmployeeHoursTable.css";

interface EmployeeHoursProps {
 data: any[];
 loading: boolean;
}

export default function EmployeeHoursTable({ data, loading }: EmployeeHoursProps) {
 if (loading) {
 return <div className="loading-state">Loading dashboard data...</div>;
 }

 if (data.length === 0) {
 return (
 <div className="empty-state">
 No approved work logs found.
 </div>
 );
 }

 return (
 <div className="hours-table-container">
 <table className="hours-table">
 <thead>
 <tr>
 <th>Employee</th>
 <th>Total Hours</th>
 </tr>
 </thead>
 <tbody>
 {data.map((item, index) => (
 <tr key={index}>
 <td>{item.groupby_fields?.[0]?.display_value || "Unknown"}</td>
 <td className="hours-cell">
 {parseFloat(item.stats?.sum?.hours_worked || "0").toFixed(1)}
 </td>
 </tr>
 ))}
 </tbody>
 </table>
 </div>
 );
}
",".hours-table-container {
 background: rgb(var(--now-container--background-color, 255, 255, 255));
