","import React from "react";
import { display } from "../utils/fields";
import "./LeaveRequestsTable.css";

interface LeaveRequestsProps {
 data: any[];
 loading: boolean;
}

export default function LeaveRequestsTable({ data, loading }: LeaveRequestsProps) {
 if (loading) {
 return <div className="loading-state">Loading leave requests...</div>;
 }

 if (data.length === 0) {
 return (
 <div className="empty-state">
 No pending or approved leave requests found.
 </div>
 );
 }

 return (
 <div className="leave-table-container">
 <table className="leave-table">
 <thead>
 <tr>
 <th>Employee</th>
 <th>Type</th>
 <th>Start Date</th>
 <th>End Date</th>
 <th>Status</th>
 </tr>
 </thead>
 <tbody>
 {data.map((item, index) => (
 <tr key={index}>
 <td>{display(item.employee)}</td>
 <td>{display(item.leave_type)}</td>
 <td>{display(item.start_date)}</td>
 <td>{display(item.end_date)}</td>
 <td>
 <span className={`status-badge status-badge--${item.status?.value || "draft"}`}>
 {display(item.status)}
 </span>
 </td>
 </tr>
 ))}
 </tbody>
 </table>
 </div>
 );
}
