",".dashboard {
 max-width: 960px;
 margin: 0 auto;
 padding: 24px;
 font-family: var(--now-font-family, "Lato", "Helvetica Neue", sans-serif);
}

.dashboard-header {
 margin-bottom: 24px;
}

.dashboard-title {
 font-size: 24px;
 font-weight: 700;
 color: rgb(var(--now-color--text--primary, 41, 41, 41));
 margin: 0 0 4px 0;
}

.dashboard-subtitle {
 font-size: 14px;
 color: rgb(var(--now-color--text--secondary, 100, 100, 100));
 margin: 0;
}

.dashboard-summary {
 display: flex;
 gap: 16px;
 margin-bottom: 32px;
 flex-wrap: wrap;
}

.summary-card {
 flex: 1;
 min-width: 160px;
 background: rgb(var(--now-container--background-color, 255, 255, 255));
 border-radius: 8px;
 padding: 20px;
 box-shadow: 0 1px 4px rgba(0, 0, 0, 0.08);
 display: flex;
 flex-direction: column;
 gap: 8px;
}

.summary-label {
 font-size: 12px;
 color: rgb(var(--now-color--text--secondary, 100, 100, 100));
 text-transform: uppercase;
 letter-spacing: 0.5px;
}

.summary-value {
 font-size: 28px;
 font-weight: 700;
 color: rgb(var(--now-actionable--primary--background-color, 0, 128, 163));
}

.summary-value--warning {
 color: rgb(var(--now-indicator--warning--color, 180, 130, 0));
}

.summary-value--positive {
 color: rgb(var(--now-indicator--positive--color, 30, 130, 30));
}

.dashboard-section {
 margin-bottom: 32px;
}

.section-title {
 font-size: 18px;
 font-weight: 600;
 color: rgb(var(--now-color--text--primary, 41, 41, 41));
 margin: 0 0 12px 0;
}
