","import React, { useEffect, useState, useMemo } from "react";
import { DashboardService } from "./services/DashboardService";
import EmployeeHoursTable from "./components/EmployeeHoursTable";
import LeaveRequestsTable from "./components/LeaveRequestsTable";
import "./app.css";

export default function App() {
 const service = useMemo(() => new DashboardService(), []);
 const [hoursData, setHoursData] = useState([]);
 const [leaveRequests, setLeaveRequests] = useState([]);
 const [leaveStats, setLeaveStats] = useState([]);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 Promise.all([
 service.getHoursPerEmployee(),
 service.getLeaveRequests(),
 service.getLeaveStats()
 ]).then(([hours, leaves, stats]) => {
 setHoursData(hours);
 setLeaveRequests(leaves);
 setLeaveStats(stats);
 setLoading(false);
 });
 }, [service]);

 const totalHours = hoursData.reduce((sum, item) => {
 return sum + parseFloat(item.stats?.sum?.hours_worked || "0");
 }, 0);

 const pendingLeaves = leaveStats.find(
 s => s.groupby_fields?.[0]?.value === "submitted"
 );
 const approvedLeaves = leaveStats.find(
 s => s.groupby_fields?.[0]?.value === "approved"
 );

 return (
 <div className="dashboard">
 <div className="dashboard-header">
 <h1 className="dashboard-title">Manager Dashboard</h1>
 <p className="dashboard-subtitle">Employee Work & Leave Overview</p>
 </div>
 <div className="dashboard-summary">
 <div className="summary-card">
 <span className="summary-label">Total Approved Hours</span>
 <span className="summary-value">{totalHours.toFixed(1)}</span>
 </div>
 <div className="summary-card">
 <span className="summary-label">Employees</span>
 <span className="summary-value">{hoursData.length}</span>
 </div>
 <div className="summary-card">
 <span className="summary-label">Pending Leave Requests</span>
 <span className="summary-value summary-value--warning">
 {pendingLeaves?.stats?.count || "0"}
 </span>
 </div>
 <div className="summary-card">
 <span className="summary-label">Approved Leaves</span>
 <span className="summary-value summary-value--positive">
 {approvedLeaves?.stats?.count || "0"}
 </span>
 </div>
 </div>

 <div className="dashboard-section">
 <h2 className="section-title">Hours Worked Per Employee</h2>
 <EmployeeHoursTable data={hoursData} loading={loading} />
 </div>

 <div className="dashboard-section">
 <h2 className="section-title">Recent Leave Requests</h2>
 <LeaveRequestsTable data={leaveRequests} loading={loading} />
 </div>
 </div>
 );
}
